m = int(input())
n = int(input())

matrix = []

for i in range(m):
    matrix.append([])
    row = input().split()
    for j in range(n):
        matrix[i].append(int(row[j]))

transpose = []

for j in range(n):
    transpose.append([])
    for i in range(m):
        transpose[j].append(matrix[i][j])

for row in transpose:
    for element in row:
        print(element, end=' ')
    print()
